Step 1: 创建 Liquibase changeset 文件 `005_space_change_record.xml`:

```xml
<?xml version="1.0" encoding="UTF-8"?>
<databaseChangeLog
        xmlns="http://www.liquibase.org/xml/ns/dbchangelog"
        xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
        xsi:schemaLocation="http://www.liquibase.org/xml/ns/dbchangelog http://www.liquibase.org/xml/ns/dbchangelog/dbchangelog-latest.xsd">

    <changeSet id="005-1" author="luobeilin">
        <createTable tableName="collabspace_space_change_record" remarks="空间站变更记录">
            <column name="id" type="bigint" remarks="主键">
                <constraints primaryKey="true" nullable="false"/>
            </column>
            <column name="space_id" type="varchar(255)" remarks="空间站ID">
                <constraints nullable="false"/>
            </column>
            <column name="type" type="tinyint" remarks="变更类型：1=子管理员变更，2=成员变更">
                <constraints nullable="false"/>
            </column>
            <column name="action" type="varchar(32)" remarks="操作：ADD/REMOVE">
                <constraints nullable="false"/>
            </column>
            <column name="operator_id" type="bigint" remarks="操作人用户ID">
                <constraints nullable="false"/>
            </column>
            <column name="target_user_id" type="bigint" remarks="被操作人用户ID">
                <constraints nullable="false"/>
            </column>
            <column name="detail" type="json" remarks="变更详情JSON"/>
            <column name="created_at" type="timestamp" defaultValueComputed="CURRENT_TIMESTAMP" remarks="创建时间">
                <constraints nullable="false"/>
            </column>
            <column name="created_by" type="bigint" remarks="创建人"/>
            <column name="updated_at" type="timestamp" defaultValueComputed="CURRENT_TIMESTAMP" remarks="更新时间"/>
            <column name="updated_by" type="bigint" remarks="更新人"/>
            <column name="is_deleted" type="tinyint unsigned" defaultValueNumeric="0" remarks="逻辑删除">
                <constraints nullable="false"/>
            </column>
        </createTable>
        <createIndex tableName="collabspace_space_change_record" indexName="idx_space_id_type">
            <column name="space_id"/>
            <column name="type"/>
        </createIndex>
    </changeSet>

</databaseChangeLog>
```

Step 2: 在 `db.changelog-master.xml` 的 `004_permission_request.xml` 后追加一行:
```xml
<include file="classpath:db/changelog/005_space_change_record.xml" relativeToChangelogFile="false" />
```

